def unique_limit(values, limit):
    out = []
    seen = set()
    for value in values:
        if not isinstance(value, str):
            continue
        trimmed = value.strip()
        if not trimmed or trimmed in seen:
            continue
        seen.add(trimmed)
        out.append(trimmed)
        if len(out) >= limit:
            break
    return out

def is_likely_key_column(name):
    normalized = str(name).strip().lower()
    return normalized in ('id', 'ref', 'key', 'code')         or normalized.endswith(('_id', '_ref', '_key', '_code'))         or 'uuid' in normalized

def normalize_candidate_key_value(value):
    if isinstance(value, str):
        trimmed = value.strip()
        return trimmed if trimmed else None
    if isinstance(value, (int, float, bool)):
        return str(value)
    return None

def build_candidate_key_hint(rows, columns):
    if not isinstance(rows, list) or len(rows) < 2 or not columns:
        return None
    null_count = 0
    non_null_count = 0
    distinct_values = set()
    for row in rows:
        if not isinstance(row, dict):
            continue
        parts = []
        has_nullish_part = False
        for column in columns:
            value = normalize_candidate_key_value(row.get(column))
            if value is None:
                has_nullish_part = True
                break
            parts.append(value)
        if has_nullish_part:
            null_count += 1
            continue
        non_null_count += 1
        distinct_values.add('\x1f'.join(parts))
    if non_null_count == 0:
        return None
    distinct_count = len(distinct_values)
    duplicate_count = max(0, non_null_count - distinct_count)
    return {
        'columns': columns,
        'sample_rows_inspected': len(rows),
        'null_count': null_count,
        'distinct_count': distinct_count,
        'duplicate_count': duplicate_count,
        'observed_unique_in_sample': null_count == 0 and duplicate_count == 0,
    }

def build_candidate_key_hints(rows, available_columns=None):
    if not isinstance(rows, list) or len(rows) < 2:
        return None
    columns = unique_limit(available_columns or [str(key) for row in rows if isinstance(row, dict) for key in row.keys()], MAX_COLUMNS)
    if not columns:
        return None
    stats_by_column = {}
    for index, column in enumerate(columns):
        hint = build_candidate_key_hint(rows, [column])
        if not hint:
            continue
        stats_by_column[column] = {
            'hint': hint,
            'index': index,
            'likely_key': is_likely_key_column(column),
        }
    if not stats_by_column:
        return None
    likely_columns = [column for column in columns if column in stats_by_column and stats_by_column[column]['likely_key']]
    fallback_columns = [
        column for column, _ in sorted(
            [(column, stats) for column, stats in stats_by_column.items() if not stats['likely_key']],
            key=lambda item: (
                -item[1]['hint']['distinct_count'],
                item[1]['hint']['null_count'],
                item[1]['index'],
            ),
        )[:MAX_FALLBACK_KEY_COLUMNS]
    ]
    selected_columns = unique_limit(likely_columns + fallback_columns, MAX_CANDIDATE_KEY_HINTS)
    hints = [stats_by_column[column]['hint'] for column in selected_columns if column in stats_by_column]
    return hints or None

def infer_format(path):
    lower = path.lower()
    if lower.endswith('.json') or lower.endswith('.jsonl') or lower.endswith('.ndjson'):
        return 'json'
    if lower.endswith('.csv'):
        return 'csv'
    if lower.endswith('.tsv'):
        return 'tsv'
    return None

def pick_object_array_candidate(value):
    for key in ['rows', 'items', 'records', 'data']:
        possible = value.get(key)
        if isinstance(possible, list) and any(isinstance(item, dict) for item in possible):
            return possible
    for possible in value.values():
        if isinstance(possible, list) and any(isinstance(item, dict) for item in possible):
            return possible
    return None

def build_child_collection_entries(value, prefix='', remaining_depth=1, remaining_budget=None):
    budget = MAX_CHILD_COLLECTIONS if remaining_budget is None else remaining_budget
    entries = {}
    if not isinstance(value, dict) or budget <= 0:
        return entries, budget
    child_keys = unique_limit(list(value.keys()), MAX_KEYS)
    for key in child_keys:
        if budget <= 0:
            break
        child = value.get(key)
        logical_key = f"{prefix}.{key}" if prefix else key
        if isinstance(child, list):
            object_rows = [row for row in child if isinstance(row, dict)]
            entry = {
                'type': 'array',
                'row_count': len(child),
            }
            if object_rows:
                sample_keys = unique_limit(list(object_rows[0].keys()), MAX_CHILD_SAMPLE_KEYS)
                if sample_keys:
                    entry['sample_keys'] = sample_keys
            entries[logical_key] = entry
            budget -= 1
            continue
        if not isinstance(child, dict):
            continue
        object_map_summary = detect_object_map_summary(child)
        if object_map_summary:
            entries[logical_key] = object_map_summary
            budget -= 1
            continue
        if remaining_depth > 0:
            nested_entries, budget = build_child_collection_entries(
                child,
                logical_key,
                remaining_depth - 1,
                budget,
            )
            if nested_entries:
                entries.update(nested_entries)
                continue
        entries[logical_key] = {'type': 'object'}
        budget -= 1
    return entries, budget

def infer_object_map_key_pattern(keys):
    if not keys:
        return 'mixed'
    if all(re.fullmatch(r'\d+', str(key or '')) for key in keys):
        return 'numeric_string'
    if all(re.fullmatch(r'[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[1-5][0-9a-fA-F]{3}-[89abAB][0-9a-fA-F]{3}-[0-9a-fA-F]{12}', str(key or '')) for key in keys):
        return 'uuid_like'
    if all(isinstance(key, str) and key.strip() for key in keys):
        return 'string'
    return 'mixed'

def detect_object_map_summary(value):
    if not isinstance(value, dict):
        return None
    keys = [str(key) for key in value.keys() if isinstance(key, str) and key.strip()]
    if len(keys) < 2:
        return None
    key_pattern = infer_object_map_key_pattern(keys)
    if key_pattern not in ('numeric_string', 'uuid_like'):
        return None
    values = [value.get(key) for key in keys]
    if not values:
        return None
    all_arrays = all(isinstance(entry, list) for entry in values)
    all_objects = all(isinstance(entry, dict) for entry in values)
    all_scalars = all(not isinstance(entry, (list, dict)) for entry in values)
    observed_kinds = sum(1 for flag in (all_arrays, all_objects, all_scalars) if flag)
    if observed_kinds != 1:
        return None
    summary = {
        'type': 'object',
        'container_kind': 'object_map',
        'entry_count': len(keys),
        'key_pattern': key_pattern,
        'sample_map_keys': unique_limit(keys, MAX_CHILD_SAMPLE_KEYS),
    }
    if all_arrays:
        summary['value_type'] = 'array'
        first_rows = next((
            [row for row in entry if isinstance(row, dict)]
            for entry in values
            if isinstance(entry, list) and any(isinstance(row, dict) for row in entry)
        ), None)
        if first_rows:
            value_sample_keys = unique_limit(list(first_rows[0].keys()), MAX_CHILD_SAMPLE_KEYS)
            if value_sample_keys:
                summary['value_sample_keys'] = value_sample_keys
    elif all_objects:
        summary['value_type'] = 'object'
        first_object = next((entry for entry in values if isinstance(entry, dict)), None)
        if first_object:
            value_sample_keys = unique_limit(list(first_object.keys()), MAX_CHILD_SAMPLE_KEYS)
            if value_sample_keys:
                summary['value_sample_keys'] = value_sample_keys
    else:
        summary['value_type'] = 'scalar'
    return summary

def resolve_child_collection_value(value, logical_key):
    current = value
    for segment in str(logical_key).split('.'):
        if not isinstance(current, dict):
            return None
        current = current.get(segment)
    return current

def build_json_schema_summary(value, format_name, inspected_bytes):
    if isinstance(value, list):
        object_rows = [row for row in value[:MAX_ROWS] if isinstance(row, dict)]
        columns = unique_limit([key for row in object_rows for key in row.keys()], MAX_COLUMNS)
        sample_row_keys = unique_limit(list(object_rows[0].keys()), MAX_KEYS) if object_rows else []
        summary = {
            'format': format_name,
            'top_level_type': 'array',
            'row_count_hint': len(value),
            'inspected_bytes': inspected_bytes,
        }
        if columns:
            summary['columns'] = columns
        if sample_row_keys:
            summary['sample_row_keys'] = sample_row_keys
        candidate_key_hints = build_candidate_key_hints(object_rows, columns)
        if candidate_key_hints:
            summary['candidate_key_hints'] = candidate_key_hints
        return summary
    if isinstance(value, dict):
        top_level_keys = unique_limit(list(value.keys()), MAX_KEYS)
        object_map_summary = detect_object_map_summary(value)
        if object_map_summary:
            summary = {
                'format': format_name,
                'top_level_type': 'object',
                'inspected_bytes': inspected_bytes,
            }
            if top_level_keys:
                summary['top_level_keys'] = top_level_keys
            for key in ('container_kind', 'entry_count', 'key_pattern', 'value_type', 'sample_map_keys', 'value_sample_keys'):
                if object_map_summary.get(key):
                    summary[key] = object_map_summary.get(key)
            return summary
        child_collections, _ = build_child_collection_entries(value, '', 1, MAX_CHILD_COLLECTIONS)

        array_children = [
            (child_key, child_summary)
            for child_key, child_summary in child_collections.items()
            if child_summary.get('type') == 'array'
        ]
        columns = None
        sample_row_keys = None
        row_count_hint = None
        columns_source_key = None
        candidate_key_hints = None
        if len(array_children) == 1:
            child_key = array_children[0][0]
            child_val = resolve_child_collection_value(value, child_key)
            if isinstance(child_val, list):
                object_rows = [row for row in child_val[:MAX_ROWS] if isinstance(row, dict)]
                columns = unique_limit([key for row in object_rows for key in row.keys()], MAX_COLUMNS)
                sample_row_keys = unique_limit(list(object_rows[0].keys()), MAX_KEYS) if object_rows else []
                row_count_hint = len(child_val)
                columns_source_key = child_key
                candidate_key_hints = build_candidate_key_hints(object_rows, columns)
        summary = {
            'format': format_name,
            'top_level_type': 'object',
            'inspected_bytes': inspected_bytes,
        }
        if top_level_keys:
            summary['top_level_keys'] = top_level_keys
        if columns:
            summary['columns'] = columns
        if sample_row_keys:
            summary['sample_row_keys'] = sample_row_keys
        if row_count_hint is not None:
            summary['row_count_hint'] = row_count_hint
        if candidate_key_hints:
            summary['candidate_key_hints'] = candidate_key_hints
        if columns_source_key:
            summary['columns_source_key'] = columns_source_key
        if child_collections:
            summary['child_collections'] = child_collections
        return summary
    return {
        'format': format_name,
        'top_level_type': 'scalar',
        'inspected_bytes': inspected_bytes,
    }

def parse_delimited_header(line, delimiter):
    columns = []
    current = ''
    in_quotes = False
    idx = 0
    while idx < len(line):
        char = line[idx]
        if char == '"':
            if in_quotes and idx + 1 < len(line) and line[idx + 1] == '"':
                current += '"'
                idx += 2
                continue
            in_quotes = not in_quotes
            idx += 1
            continue
        if char == delimiter and not in_quotes:
            columns.append(current)
            current = ''
            idx += 1
            continue
        current += char
        idx += 1
    columns.append(current)
    return unique_limit([column.lstrip('\ufeff').strip() for column in columns], MAX_COLUMNS)

def infer_tabular_summary_from_text(text, format_name, inspected_bytes):
    delimiter = ',' if format_name == 'csv' else '\t'
    rows = []
    reader = csv.DictReader(text.splitlines(), delimiter=delimiter)
    for idx, row in enumerate(reader):
        if idx >= MAX_ROWS:
            break
        rows.append(row)
    columns = unique_limit(reader.fieldnames or [], MAX_COLUMNS)
    if not columns:
        first_line = None
        for candidate in text.splitlines():
            if candidate.strip():
                first_line = candidate.rstrip()
                break
        columns = parse_delimited_header(first_line, delimiter) if first_line else []
    sample_row_keys = unique_limit(list(rows[0].keys()), MAX_KEYS) if rows else []
    summary = {
        'format': format_name,
        'top_level_type': 'table',
        'inspected_bytes': inspected_bytes,
    }
    if columns:
        summary['columns'] = columns
    if sample_row_keys:
        summary['sample_row_keys'] = sample_row_keys
    if rows:
        summary['row_count_hint'] = len(rows)
    candidate_key_hints = build_candidate_key_hints(rows, columns)
    if candidate_key_hints:
        summary['candidate_key_hints'] = candidate_key_hints
    return summary

def infer_schema_summary(path, size_bytes):
    format_name = infer_format(path)
    if not format_name:
        return None
    if format_name == 'pdf':
        return {
            'format': format_name,
            'top_level_type': 'binary',
            'skipped_reason': 'unsupported_format',
            'inspected_bytes': size_bytes,
        }
    if size_bytes is not None and size_bytes > MAX_BYTES:
        return {
            'format': format_name,
            'skipped_reason': 'file_too_large',
            'inspected_bytes': size_bytes,
        }
    try:
        with open(path, 'r', encoding='utf-8') as handle:
            text = handle.read(MAX_BYTES + 1)
    except UnicodeDecodeError:
        return {
            'format': format_name,
            'skipped_reason': 'binary_or_non_utf8',
            'inspected_bytes': size_bytes,
        }
    inspected_bytes = len(text.encode('utf-8'))
    if inspected_bytes > MAX_BYTES:
        return {
            'format': format_name,
            'skipped_reason': 'file_too_large',
            'inspected_bytes': inspected_bytes,
        }
    if format_name == 'json':
        try:
            lower = path.lower()
            if lower.endswith('.jsonl') or lower.endswith('.ndjson'):
                rows = []
                for raw_line in text.splitlines():
                    line = raw_line.strip()
                    if not line:
                        continue
                    rows.append(json.loads(line))
                    if len(rows) >= MAX_ROWS:
                        break
                object_rows = [row for row in rows if isinstance(row, dict)]
                columns = unique_limit([key for row in object_rows for key in row.keys()], MAX_COLUMNS)
                sample_row_keys = unique_limit(list(object_rows[0].keys()), MAX_KEYS) if object_rows else []
                summary = {
                    'format': 'json',
                    'top_level_type': 'array',
                    'row_count_hint': len(rows),
                    'inspected_bytes': inspected_bytes,
                }
                if columns:
                    summary['columns'] = columns
                if sample_row_keys:
                    summary['sample_row_keys'] = sample_row_keys
                candidate_key_hints = build_candidate_key_hints(object_rows, columns)
                if candidate_key_hints:
                    summary['candidate_key_hints'] = candidate_key_hints
                return summary
            return build_json_schema_summary(json.loads(text), format_name, inspected_bytes)
        except Exception:
            return {
                'format': 'json',
                'skipped_reason': 'unparseable_json',
                'inspected_bytes': inspected_bytes,
            }
    return infer_tabular_summary_from_text(text, format_name, inspected_bytes)

def compute_sha256(path, size_bytes):
    if size_bytes is not None and size_bytes > MAX_BYTES:
        return None
    digest = hashlib.sha256()
    with open(path, 'rb') as handle:
        while True:
            chunk = handle.read(65536)
            if not chunk:
                break
            digest.update(chunk)
    return digest.hexdigest()

