invoice_lookup = {}
for inv in invoices:
    if isinstance(inv, dict) and inv.get('invoice_id') is not None:
        invoice_lookup[str(inv['invoice_id'])] = inv

sequence = 1
accepted = []
rejected = []
approval_required = []

for idx, cand in enumerate(candidates, start=1):
    if not isinstance(cand, dict):
        raise TypeError(f'Candidate #{idx} is not an object: {type(cand).__name__}')
    invoice_id = cand.get('invoice_id')
    correction_amount = cand.get('correction_amount')
    reason_code = cand.get('reason_code')
    evidence_refs = cand.get('evidence_refs') or []
    status = cand.get('status')
    invoice_status = invoice_lookup.get(str(invoice_id), {}).get('invoice_status', cand.get('invoice_status'))
    base = {
        'invoice_id': invoice_id,
        'correction_amount': correction_amount,
        'reason_code': reason_code,
        'evidence_refs': evidence_refs,
    }

    if status == 'rejected':
        rejected.append({**base, 'rejection_reason': cand.get('rejection_reason')})
        continue
    if status != 'eligible':
        raise ValueError(f"Unexpected candidate status for invoice_id={invoice_id!r}: {status!r}")

    if correction_amount is None:
        raise ValueError(f'missing correction_amount for invoice_id={invoice_id!r}')
    if invoice_status == 'paid_locked':
