        continue
    if correction_amount > 100:
        rejected.append({**base, 'rejection_reason': 'exceeds_max_correction'})
        continue

    corr_id = f'CORR-{sequence:04d}'
    sequence += 1
    if correction_amount > 25:
        approval_required.append({**base, 'correction_id': corr_id, 'approval_required': True})
    else:
        accepted.append({**base, 'correction_id': corr_id, 'approval_required': False})

result = {
    'accepted': accepted,
    'rejected': rejected,
    'approval_required': approval_required,
}

# Validate output contract before writing.
if set(result.keys()) != {'accepted', 'rejected', 'approval_required'}:
    raise AssertionError(f'Unexpected top-level keys: {list(result.keys())}')
for key, value in result.items():
