        raise TypeError(f'{key} is not a list')

output_total = sum(len(v) for v in result.values())
if output_total != len(candidates):
    raise AssertionError(f'Output total {output_total} does not match input candidate count {len(candidates)}')

for bucket_name in ('accepted', 'approval_required'):
    for item in result[bucket_name]:
        amt = item.get('correction_amount')
        if amt is not None and amt > 100:
            raise AssertionError(f'Invalid {bucket_name} item exceeds max correction: {item}')
